		t.Fatalf("found unannotated mcpContent{Type:\"text\"} literal sites in server.go (each must use evidence.ClampOutput via the mcpText helper, or carry //evidence:allow-unbounded). Sites:\n  %s",
			strings.Join(problems, "\n  "))
	}
